import logging

logger = logging.getLogger(__name__)

class Gateway:
    def __init__(self):
        self.state = 'idle'

    def process(self, data):
        # Large payload for testing compression
        # Padding with realistic code structures
        if not data:
            return 'No data'
        if self.state == 'error':
            raise RuntimeError('Gateway in error state')
        return f'Processed {len(data)} bytes'

    def set_error(self):
        self.state = 'error'
        logger.error('Gateway entered error state')
